function sleep(ms){return new Promise(function(r){setTimeout(r,ms);});}
function pageText(){var t=(document.title||'').toLowerCase();var b=(document.body?document.body.innerText:'')||'';return t+' '+b.toLowerCase();}
function networkErr(){var s=pageText();return s.includes("this site can't be reached")||s.includes("this site can’t be reached")||s.includes('err_connection')||s.includes('err_tunnel')||s.includes('err_proxy')||s.includes('err_timed_out')||s.includes('dns_probe_finished')||s.includes('check if there is a typo');}
function vis(el){if(!el)return false;var r=el.getBoundingClientRect();var s=getComputedStyle(el);return r.width>0&&r.height>0&&s.visibility!=='hidden'&&s.display!=='none';}
function emailReady(){var sels=['input[name="Email"]','#input-54','input[type="email"]','form input'];for(var i=0;i<sels.length;i++){var el=document.querySelector(sels[i]);if(vis(el))return true;}return false;}
var start=Date.now();
while(document.readyState!=='complete'&&Date.now()-start<45000){await sleep(200);}
var deadline=Date.now()+25000;
while(Date.now()<deadline){
  if(networkErr()) throw new Error('OASIS unreachable (proxy/network) - rotate proxy.');
  if(emailReady()) return (document.title||'').trim();
  await sleep(500);
}
if(networkErr()) throw new Error('OASIS unreachable (proxy/network) - rotate proxy.');
throw new Error('OASIS signup page did not load an email field in time.');

function sleep(ms){return new Promise(function(r){setTimeout(r,ms);});}
async function tryGet(u,map){try{var r=await fetch(u,{cache:'no-store'});if(!r.ok)return null;var j=await r.json();var g=map(j);return (g&&g.cc)?g:null;}catch(e){return null;}}
var g = await tryGet('https://ipapi.co/json/',function(j){return {city:j.city,region:j.region,cc:(j.country_code||'').toUpperCase(),calling:String(j.country_calling_code||'').replace('+','')};})
     || await tryGet('https://ipwho.is/',function(j){return {city:j.city,region:j.region,cc:(j.country_code||'').toUpperCase(),calling:String(j.calling_code||'').replace('+','')};})
     || await tryGet('https://get.geojs.io/v1/ip/geo.json',function(j){return {city:j.city,region:j.region,cc:(j.country_code||'').toUpperCase(),calling:''};});
if(!g||!g.cc) throw new Error('Could not resolve the proxy geo (IP geolocation failed) - check/rotate the proxy.');
if(!g.city) g.city=g.region||'';
return g;

