function vis(el){if(!el)return false;var r=el.getBoundingClientRect();var s=getComputedStyle(el);return r.width>0&&r.height>0&&s.visibility!=='hidden'&&s.display!=='none';}
function textInputs(){return Array.from(document.querySelectorAll('input')).filter(function(i){var t=(i.type||'').toLowerCase();return vis(i)&&(t===''||t==='text');});}
function setVal(el,val){el.focus();var s=Object.getOwnPropertyDescriptor(window.HTMLInputElement.prototype,'value').set;s.call(el,val);el.dispatchEvent(new Event('input',{bubbles:true}));el.dispatchEvent(new Event('change',{bubbles:true}));el.dispatchEvent(new Event('blur',{bubbles:true}));}
function after(ref,el){return !!ref && !!(ref.compareDocumentPosition(el)&Node.DOCUMENT_POSITION_FOLLOWING);}
var deadline=Date.now()+10000;
while(Date.now()<deadline){
  var box=Array.from(document.querySelectorAll('.v-input--selection-controls input[type="checkbox"], input[type="checkbox"]')).filter(vis)[0];
  if(box){
    if(box.checked) return 'agree-checked';
    var wrap=box.closest('.v-input--selection-controls')||box.parentElement;
    var target=(wrap&&wrap.querySelector('.v-input--selection-controls__ripple'))||wrap||box;
    target.scrollIntoView({block:'center'}); target.click(); await sleep(300);
    if(box.checked) return 'agree-checked';
    box.click(); await sleep(300);
    if(box.checked) return 'agree-checked';
  }
  await sleep(300);
}
return 'no-agree-checkbox';

