function pick(a){return a[Math.floor(Math.random()*a.length)];}
var cc=String("{{vars.geo.cc}}"||"").toUpperCase();
var gens={
  US:function(){return pick('23456789'.split(''))+d(2)+pick('23456789'.split(''))+d(6);},
  GB:function(){return '7'+pick(['4','7','8','9'])+d(8);},
  IE:function(){return '8'+pick(['3','5','6','7','9'])+d(7);},
  ES:function(){return pick(['6','7'])+d(8);},
  FR:function(){return pick(['6','7'])+d(8);},
  DE:function(){return '15'+d(9);},
  IT:function(){return '3'+pick(['1','2','3','4','5','6','8'])+d(8);},
  NL:function(){return '6'+d(8);},
  AU:function(){return '4'+d(8);},
  PT:function(){return '9'+pick(['1','2','3','6'])+d(7);},
  BE:function(){return '4'+pick(['5','6','7','8','9'])+d(7);},
  PL:function(){return pick(['5','6','7','8'])+d(8);},
  SE:function(){return '7'+pick(['0','2','3','6','9'])+d(7);},
  CH:function(){return '7'+pick(['5','6','7','8','9'])+d(7);},
  AT:function(){return '6'+pick(['5','6','7','8','9'])+d(8);},
  BR:function(){return pick(['11','21','31','41','51','61','71','81'])+'9'+d(8);},
  MX:function(){return '1'+d(9);}
};
gens.CA=gens.US;
